// In-memory product store — simulates a database that gets refreshed
// from upstream ERP/PIM systems during a catalog sync.
let products = [
  { id: 1, name: 'Laptop', price: 999, inStock: true, updatedAt: null },
  { id: 2, name: 'Phone', price: 699, inStock: true, updatedAt: null },
  { id: 3, name: 'Tablet', price: 499, inStock: false, updatedAt: null },
  { id: 4, name: 'Headphones', price: 199, inStock: true, updatedAt: null },
  { id: 5, name: 'Watch', price: 299, inStock: true, updatedAt: null },
];

/**
 * Returns a snapshot of the current product catalog.
 * Simulates a 100 ms database read delay.
 */
export async function getAllProducts() {
  await new Promise((resolve) => setTimeout(resolve, 100));
  return products.map((p) => ({ ...p }));
}

/**
 * Simulates a long-running sync from an upstream ERP/PIM system.
 * Updates prices, availability, and the sync timestamp to mimic
 * real data that changes between refresh cycles.
 *
 * In production this would call external APIs, transform data, and
 * write to a primary database — the read cache is invalidated
 * separately via revalidateTag("products").
 */
export async function syncProducts() {
  // Simulate upstream fetch / transform time
  await new Promise((resolve) => setTimeout(resolve, 4000));

  const now = new Date().toISOString();

  products = products.map((p) => ({
    ...p,
    price: Math.round((p.price + (Math.random() - 0.5) * 60)) || 1,
    inStock: Math.random() > 0.2,
    updatedAt: now,
  }));

  console.log('[Sync] Catalog sync completed at', now);
}

import { unstable_cache } from 'next/cache';
import { getAllProducts } from './db';

/**
 * Cached product catalog query.
 *
 * Uses Next.js unstable_cache to memoize product data with the "products"
 * cache tag. This ensures that reads are fast while still allowing
 * targeted invalidation via revalidateTag("products") when the upstream
 * catalog sync completes.
 *
 * Cache key includes "products-list" for deduplication — the "products"
 * tag is used consistently for cross-cutting invalidation.
 */
export const getCachedProducts = unstable_cache(
  async () => {
    console.log('[Products Cache] Miss — fetching from database');
    return getAllProducts();
  },
  ['products-list'],
  {
    tags: ['products'],
  },
);

import { revalidateTag } from 'next/cache';
import { after } from 'next/server';
import { getCachedProducts } from '@/lib/products';
import { syncProducts } from '@/lib/db';

/* ── styles ───────────────────────────────────────────── */

const pageStyle: React.CSSProperties = {
  maxWidth: 960,
  margin: '0 auto',
  padding: '32px 24px',
  fontFamily:
    '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif',
};

const headerStyle: React.CSSProperties = {
  display: 'flex',
  justifyContent: 'space-between',
  alignItems: 'flex-start',
  flexWrap: 'wrap',
  gap: 16,
  marginBottom: 24,
};

const headingStyle: React.CSSProperties = {
  fontSize: 24,
  fontWeight: 600,
  margin: 0,
};

const badgeBase: React.CSSProperties = {
  display: 'inline-block',
  fontSize: 12,
  fontWeight: 600,
  padding: '4px 10px',
  borderRadius: 6,
  textTransform: 'uppercase',
  letterSpacing: '0.03em',
};

const syncButtonStyle: React.CSSProperties = {
  ...badgeBase,
  background: '#2563eb',
  color: '#fff',
  border: 'none',
  cursor: 'pointer',
};

const tableStyle: React.CSSProperties = {
  width: '100%',
  borderCollapse: 'collapse',
  fontSize: 14,
};

const thStyle: React.CSSProperties = {
  textAlign: 'left',
  padding: '10px 12px',
  borderBottom: '2px solid #e2e8f0',
  fontWeight: 600,
  color: '#475569',
};

const tdStyle: React.CSSProperties = {
  padding: '10px 12px',
  borderBottom: '1px solid #e2e8f0',
  verticalAlign: 'middle',
};

const stockBadge = (inStock: boolean): React.CSSProperties => ({
  ...badgeBase,
  background: inStock ? '#dcfce7' : '#fee2e2',
  color: inStock ? '#166534' : '#991b1b',
});

const syncBarStyle: React.CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: 12,
  padding: '12px 16px',
  borderRadius: 8,
  marginBottom: 24,
  fontSize: 14,
};

/* ── page ─────────────────────────────────────────────── */

export default function AdminProductsPage() {
  /* ── inline Server Action ──────────────────────────── */
  async function syncLatestCatalog() {
    'use server';

    // 1. Invalidate every cached read tagged "products".
    //    Subsequent requests to any view that uses this tag will
    //    fetch fresh data from the database.
    revalidateTag('products');

    // 2. Kick off the long-running upstream sync *after* the HTTP
    //    response is sent so the admin sees an immediate reply and
    //    can continue working.  The product list is briefly stale
    //    until the background job completes and the next page load
    //    reads updated data.
    after(async () => {
      await syncProducts();
    });
  }

  /* ── cached data ───────────────────────────────────── */
  const products = getCachedProducts();

  const hasBeenSynced = products.some((p) => p.updatedAt !== null);
  const lastSyncAt = hasBeenSynced
    ? new Intl.DateTimeFormat('en-US', {
        dateStyle: 'medium',
        timeStyle: 'short',
      }).format(
        new Date(
          Math.max(...products.map((p) => new Date(p.updatedAt!).getTime())),
        ),
      )
    : null;

  return (
    <div style={pageStyle}>
      {/* ── header ──────────────────────────────────── */}
      <div style={headerStyle}>
        <div>
          <h1 style={headingStyle}>Product Catalog</h1>
          <p style={{ margin: '4px 0 0', color: '#64748b', fontSize: 14 }}>
            Cached with tag &quot;products&quot; &middot;{' '}
            {products.length} SKUs
          </p>
        </div>

        <form>
          <button type="submit" formAction={syncLatestCatalog} style={syncButtonStyle}>
            Sync latest catalog
          </button>
        </form>
      </div>

      {/* ── sync status ─────────────────────────────── */}
      {lastSyncAt ? (
        <div style={{ ...syncBarStyle, background: '#f0fdf4', color: '#166534', border: '1px solid #bbf7d0' }}>
          <span>&#10003;</span>
          <span>
            Catalog sync completed — products last refreshed{' '}
            <strong>{lastSyncAt}</strong>. Data shown is the latest
            cached snapshot; a new sync will update it in the background.
          </span>
        </div>
      ) : (
        <div style={{ ...syncBarStyle, background: '#fffbeb', color: '#92400e', border: '1px solid #fde68a' }}>
          <span>&#9432;</span>
          <span>
            Products loaded from cache. Use <strong>Sync latest catalog</strong>{' '}
            to refresh from the upstream ERP/PIM system. The cache is tagged
            with &quot;products&quot; and will be invalidated across all views
            after a sync.
          </span>
        </div>
      )}

      {/* ── product table ───────────────────────────── */}
      <table style={tableStyle}>
        <thead>
          <tr>
            <th style={thStyle}>SKU</th>
            <th style={thStyle}>Name</th>
            <th style={thStyle}>Price</th>
            <th style={thStyle}>Availability</th>
            <th style={thStyle}>Last Updated</th>
          </tr>
        </thead>
        <tbody>
          {products.map((product) => (
            <tr key={product.id}>
              <td style={tdStyle}>{product.id}</td>
              <td style={tdStyle}>{product.name}</td>
              <td style={tdStyle}>${product.price.toFixed(2)}</td>
              <td style={tdStyle}>
                <span style={stockBadge(product.inStock)}>
                  {product.inStock ? 'In Stock' : 'Out of Stock'}
                </span>
              </td>
              <td style={{ ...tdStyle, color: '#64748b', fontSize: 13 }}>
                {product.updatedAt
                  ? new Intl.DateTimeFormat('en-US', {
                      dateStyle: 'medium',
                      timeStyle: 'short',
                    }).format(new Date(product.updatedAt))
                  : '—'}
              </td>
            </tr>
          ))}
        </tbody>
      </table>

      {/* ── eventual-consistency explanation ────────── */}
      <div
        style={{
          marginTop: 24,
          padding: '12px 16px',
          borderRadius: 8,
          background: '#f8fafc',
          border: '1px solid #e2e8f0',
          fontSize: 13,
          color: '#64748b',
        }}
      >
        <strong style={{ color: '#334155' }}>How caching works</strong>
        <ul style={{ margin: '6px 0 0', paddingLeft: 20 }}>
          <li>
            Product data is cached with the <code>products</code> cache tag so
            browsing the catalog feels instant.
          </li>
          <li>
            Triggering a <strong>Sync latest catalog</strong> immediately
            invalidates the <code>products</code> tag across all views via{' '}
            <code>revalidateTag</code>.
          </li>
          <li>
            The upstream ERP/PIM sync runs in the background (
            <code>next/server.after</code>) so you can continue working
            straight away — the data is eventually consistent.
          </li>
          <li>
            The next page load (or any view that reads from the{' '}
            <code>products</code> cache tag) will fetch the updated catalog.
          </li>
        </ul>
      </div>
    </div>
  );
}

